{"code": "import json

# Load Europe metadata
europe_file_path = locals()['var_functions.query_db:12']
with open(europe_file_path, 'r') as f:
    europe_metadata = json.load(f)

# Organize by year
yearly_data = {}
for item in europe_metadata:
    year = item['publication_date'][:4]
    if year not in yearly_data:
        yearly_data[year] = []
    yearly_data[year].append(item['article_id'])

# Show distribution
yearly_counts = {year: len(ids) for year, ids in yearly_data.items()}
sorted_years = sorted(yearly_counts.items())

print('__RESULT__:')
print(json.dumps({
    'yearly_counts': dict(sorted_years),
    '2010_count': yearly_counts.get('2010', 0),
    'total_articles': len(europe_metadata)
}))"}

